import { num, parseColor } from "./color.mjs";
import {
  camel,
  colors,
  durationMs,
  easings,
  font,
  px,
  scale,
} from "./model.mjs";

const HEADER = `// Houston design tokens — SwiftUI constants.
// AUTO-GENERATED by @houston/design-tokens. Do NOT edit by hand.
// Copy or code-generate this file into the iOS app target at build time.
//
// Colours are theme pairs: the app resolves them with its own theme state
// (HoustonTheme) rather than the system appearance, matching how the
// web/desktop app toggles [data-theme].

import SwiftUI

public enum HoustonTheme { case light, dark }

public struct HoustonThemedColor {
    public let light: Color
    public let dark: Color
    public init(light: Color, dark: Color) {
        self.light = light
        self.dark = dark
    }
    public func resolve(_ theme: HoustonTheme) -> Color {
        theme == .dark ? dark : light
    }
}

private func rgba(_ r: Double, _ g: Double, _ b: Double, _ a: Double) -> Color {
    Color(.sRGB, red: r, green: g, blue: b, opacity: a)
}`;

function color(value) {
  const { r, g, b, a } = parseColor(value);
  return `rgba(${num(r)}, ${num(g)}, ${num(b)}, ${num(a)})`;
}

const WEIGHTS = { 400: ".regular", 500: ".medium", 600: ".semibold" };

function enumBlock(name, lines) {
  return `public enum ${name} {\n${lines.map((l) => `    ${l}`).join("\n")}\n}`;
}

export function buildSwift(light, dark) {
  const lightMap = new Map(colors(light).map((c) => [c.name, c.value]));
  const colorLines = colors(dark).map(
    (c) =>
      `public static let ${camel(c.name)} = HoustonThemedColor(light: ${color(
        lightMap.get(c.name),
      )}, dark: ${color(c.value)})`,
  );

  const cgFloat = (entries, prefix) =>
    entries.map(
      (e) =>
        `public static let ${prefix}${camel(e.name)}: CGFloat = ${px(e.value)}`,
    );

  const parts = [
    HEADER,
    "",
    enumBlock("HoustonColors", colorLines),
    "",
    enumBlock("HoustonSpacing", cgFloat(scale(light, "space"), "space")),
    "",
    enumBlock("HoustonRadius", cgFloat(scale(light, "radius"), "")),
    "",
    enumBlock("HoustonFontSize", cgFloat(font(light, "size"), "")),
    "",
    enumBlock(
      "HoustonFontWeight",
      font(light, "weight").map(
        (w) =>
          `public static let ${w.name}: Font.Weight = ${WEIGHTS[w.value] ?? ".regular"}`,
      ),
    ),
    "",
    enumBlock(
      "HoustonFontFamily",
      font(light, "family").map(
        (f) => `public static let ${f.name} = ${JSON.stringify(f.value)}`,
      ),
    ),
    "",
    enumBlock(
      "HoustonDuration",
      scale(light, "duration").map(
        (d) =>
          `public static let ${d.name}: TimeInterval = ${durationMs(d.value) / 1000}`,
      ),
    ),
    "",
    enumBlock(
      "HoustonEasing",
      easings(light).map(
        (e) =>
          `public static let ${e.name}: (Double, Double, Double, Double) = (${e.value.join(", ")})`,
      ),
    ),
    "",
  ];
  return parts.join("\n");
}
